import{_ as t,c as e,o as i,ag as s}from"./chunks/framework.DPDPlp3K.js";const g=JSON.parse('{"title":"リポジトリの作成","description":"","frontmatter":{},"headers":[],"relativePath":"text/chapter-1/make-repo.md","filePath":"text/chapter-1/make-repo.md"}'),p={name:"text/chapter-1/make-repo.md"};function r(o,a,l,d,n,c){return i(),e("div",null,a[0]||(a[0]=[s('<h1 id="リポジトリの作成" tabindex="-1">リポジトリの作成 <a class="header-anchor" href="#リポジトリの作成" aria-label="Permalink to &quot;リポジトリの作成&quot;">​</a></h1><p>前編の目標は、Git と Gitea を組み合わせてクラウドストレージとして扱えるようになることです。この章では Gitea 上に Git リポジトリを作成し、手元の環境に複製（クローン）するところまでを行います。</p><h2 id="git-の役割" tabindex="-1">Git の役割 <a class="header-anchor" href="#git-の役割" aria-label="Permalink to &quot;Git の役割&quot;">​</a></h2><p>一言でいえば Git とは「<strong>ファイルのバージョン管理ツール</strong>」です。</p><p>今はとりあえず「複数人の開発における複雑なバージョン管理を手助けしてくれる」という程度のことを押さえていただければよいと思います。具体的に Git を使うことで何ができるのか、どういう部分が便利なのかは実際に手を動かしていくと段々と分かってくるはずです。</p><p>Git の操作に慣れるために、まず共同開発のことは忘れて個人的な用途に供してみましょう。最も簡単なところでは、Gitea と組み合わせて使うことで <strong>無料のクラウドストレージ</strong> 的な使い方ができます。Gitea についての説明は後に回して、まずは何ができるかを見てみましょう。</p><div class="info custom-block"><p class="custom-block-title">便利なクラウドストレージ</p><p>Mac ユーザーなら iCloud Drive に馴染みが深いでしょう。私（このページの著者）は自宅に Mac mini を置いて大学には MacBook を持っていくので、授業の資料は iCloud Drive に置いて両方から見られるようにしています。両方がインターネットに繋がっていれば、一方を更新すると他方にも反映されます。資料のデータそのものは両方に保存されていて、オフラインでも資料を閲覧することはできます。</p><p>Microsoft が提供する OneDrive にも同様の機能がありますね。このようなクラウドストレージサービスとほぼ同じことが Git と Gitea によって実現できます。それを試してみましょう。</p></div><h2 id="リポジトリの作成-1" tabindex="-1">リポジトリの作成 <a class="header-anchor" href="#リポジトリの作成-1" aria-label="Permalink to &quot;リポジトリの作成&quot;">​</a></h2><p>Gitea のページから <a href="https://git-lecture.trap.jp/repo/create" target="_blank" rel="noreferrer">新しいリポジトリを作成</a> します。</p><ul><li>リポジトリ名を &quot;mydrive&quot; とする</li><li>リポジトリの初期設定にチェックを入れる</li></ul><p>以上のように設定して最下部の「リポジトリを作成」ボタンを押してください。</p><p><img src="https://md.trap.jp/uploads/upload_56c165c7bbf7b3894e1f42d953dad939.png" alt=""></p><p>リポジトリが作成されるとこんな画面に飛びます。</p><p><img src="https://md.trap.jp/uploads/upload_b792362e59da0e3b0632dd4c8d1f022d.png" alt=""></p><p>橙色の丸で囲ったボタンをクリックして以下の URL を入手します。よく目にする <code>https://</code> から始まる URL と異なり、SSH プロトコルによる暗号化がなされています。Web 上のリポジトリの在処を示す文字列であるという点は同じです。</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-dark github-dark vp-code" tabindex="0"><code><span class="line"><span>ssh://git@git.trap.jp:2200/{ユーザー名}/mydrive.git</span></span></code></pre></div><h2 id="リポジトリのクローン" tabindex="-1">リポジトリのクローン <a class="header-anchor" href="#リポジトリのクローン" aria-label="Permalink to &quot;リポジトリのクローン&quot;">​</a></h2><p>iCloud Drive や OneDrive では、特定の名前（たとえば「iCloud Drive」）がついた単一のディレクトリが与えられ、その中の好きな場所にファイルを置いておけるという感じでした。</p><p><img src="https://md.trap.jp/uploads/upload_463a69fe38aad51ec9417420d5723876.png" alt=""></p><p>Git + Gitea でクラウドストレージを作る場合、前に挙げたクラウドストレージと異なり、<strong>同期されるディレクトリはどこでもよい</strong>です。より正確には、ターミナル上であるディレクトリに移動して以下のコマンドを実行したとき、そこが同期されるディレクトリになります。</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-dark github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#B392F0;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#9ECBFF;--shiki-dark:#9ECBFF;"> git</span><span style="--shiki-light:#9ECBFF;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#9ECBFF;--shiki-dark:#9ECBFF;"> {先ほどの</span><span style="--shiki-light:#9ECBFF;--shiki-dark:#9ECBFF;"> URL}</span></span></code></pre></div><p>たとえば「デスクトップ」ディレクトリで上を実行してみると、README.md（と .git という隠しディレクトリ）を積んだディレクトリ mydrive が現れます。これは GitHub というオンライン上のサービスで先ほど作成した <strong>Git リポジトリ</strong> の写しになっています。</p><div class="tip custom-block"><p class="custom-block-title">ターミナル上でのディレクトリ間の移動</p><p>ターミナル上で特定のディレクトリに移動するには <code>cd</code>（<strong>C</strong>hange <strong>D</strong>irectory）コマンドが使えます。たとえば以下のコマンドを実行することで「デスクトップ」ディレクトリに移動できます。</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-dark github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#B392F0;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#9ECBFF;--shiki-dark:#9ECBFF;"> cd</span><span style="--shiki-light:#9ECBFF;--shiki-dark:#9ECBFF;"> ~/Desktop</span></span></code></pre></div><p><code>cd</code> はターミナルを扱うときに最も頻繁に実行するコマンドであると言っても過言ではありません。プログラミング基礎講習会の <a href="https://pg-basic.trap.show/text/chapter-1/terminal.html#_1-2-2-%E4%BD%9C%E6%A5%AD%E7%92%B0%E5%A2%83%E3%81%AE%E4%BD%9C%E6%88%90" target="_blank" rel="noreferrer">第 1 章</a> でもちらっと触れられているので、忘れかけていた方は復習しておくと良いでしょう。</p></div><p>このあと同期のテストをするときに必要になるので「ダウンロード」ディレクトリでも <code>clone</code> コマンドを実行しておいてください。</p><p>デスクトップとダウンロード（Windows 環境の方は WSL2 内のもの）にディレクトリ mydrive がそれぞれ一つずつ存在することが確認できたら次に進んでください。</p>',25)]))}const k=t(p,[["render",r]]);export{g as __pageData,k as default};
